    [System.IO.File]::WriteAllBytes($TempZip, [Convert]::FromBase64String(($ZipBase64 -replace "\s", "")))
    Write-Host "PASS temporary zip written: $TempZip"

    Expand-Archive -LiteralPath $TempZip -DestinationPath $Root -Force
    Write-Host "PASS package extracted"

    $Expected = @{
        "ACTIVE_GUIDES\README_START_HERE.txt" = "313914b8942656a637260056387d99bb3d89dfddd5886ab9422aea92e42d3d89"
        "ACTIVE_GUIDES\CLEAN_SEED_WRAP_GUIDE.txt" = "1fa19a2bd7dea94f1a0dfb226cb68fdc4e7423088741f8efee750e590ef66fd7"
        "ACTIVE_GUIDES\CLEAN_SEED_ALIGNMENT_CHECK.txt" = "943c7b21ff61eac91908c4dafdc282835b8d487ee0206eaa3d3f89cc09baf610"
    }

    foreach ($rel in $Expected.Keys) {
        $Path = Join-Path $Base $rel
        if (!(Test-Path $Path)) {
            throw "missing expected file: $Path"
        }
        $Hash = (Get-FileHash -Algorithm SHA256 -LiteralPath $Path).Hash.ToLower()
        if ($Hash -ne $Expected[$rel]) {
            throw "hash mismatch for $rel expected $($Expected[$rel]) got $Hash"
        }
        Write-Host "PASS verified $rel"
    }

    if (!(Test-Path (Join-Path $Base "PROOF_HISTORY"))) { throw "missing PROOF_HISTORY folder" }
    if (!(Test-Path (Join-Path $Base "LIVE_SEED_TEST_001"))) { throw "missing LIVE_SEED_TEST_001 folder" }

    Write-Host "PASS proof/history folder exists"
    Write-Host "PASS live test folder exists"
    Write-Host "PASS install complete: CLEAN_SEED_PATCH_SCOPE_STATE_TRIGGER_LOCK"
    Write-Host "OPENING: $Base"
    Invoke-Item $Base
}
catch {
    Write-Host "FAIL install error"
    Write-Host $_.Exception.Message
    Write-Host "No clean PASS. Send these FAIL lines back."
    exit 1
}
